import React, { useState, useEffect } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { formatDisplayName } from '../utils/nameFormatter';
import { gamesAPI } from '../services/api';
import { showNotification } from '../assets/notifications';
import { mockGames, Game } from '../data/mockGames';

const Home: React.FC = () => {
  const [games, setGames] = useState<Game[]>([]);
  const [loading, setLoading] = useState(true);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [searchParams] = useSearchParams();
  const [filters, setFilters] = useState({
    platform: '',
    region: '',
    priceRange: 'all'
  });
  const [searchQuery, setSearchQuery] = useState('');
  const navigate = useNavigate();
  const { state } = useAuth();

  // Get search query from URL
  const queryFromUrl = searchParams.get('query') || '';

  // Load favorites from localStorage
  useEffect(() => {
    const savedFavorites = JSON.parse(localStorage.getItem('favorites') || '[]');
    setFavorites(savedFavorites.map((game: Game) => game._id));
  }, []);

  const addToCart = (game: Game) => {
    if (!state.isAuthenticated) {
      alert('يجب تسجيل الدخول أولاً!');
      return;
    }

    // Add to cart logic here
    const cart = JSON.parse(localStorage.getItem('cart') || '[]');
    cart.push(game);
    localStorage.setItem('cart', JSON.stringify(cart));

    // Play notification sound
    const audio = new Audio('/notification.mp3');
    audio.play().catch(() => {});

    alert('تمت إضافة اللعبة للسلة بنجاح!');

    // Navigate to cart page
    navigate('/cart');
  };

  const toggleFavorite = (game: Game) => {
    const favIds = [...favorites];
    const index = favIds.indexOf(game._id);

    if (index > -1) {
      favIds.splice(index, 1);
    } else {
      favIds.push(game._id);
    }

    setFavorites(favIds);
    localStorage.setItem('favorites', JSON.stringify(favIds.map(id => games.find(g => g._id === id)).filter(Boolean)));
  };

  const loadGames = async () => {
    setLoading(true);
    try {
      const response = await gamesAPI.getGames();
      if (response.data) {
        setGames(response.data);
      } else {
        setGames(mockGames);
      }
    } catch (error) {
      console.log('Using mock games due to API error');
      setGames(mockGames);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadGames();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-red-900 to-slate-900">
      {/* Hero Section */}
      <section className="relative overflow-hidden py-20">
        <div className="absolute inset-0 bg-gradient-to-r from-red-600/20 to-orange-600/20"></div>
        <div className="w-full text-center">
          <h1 className="text-6xl md:text-8xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-orange-600 mb-6">
            {state.user ? (
              <span>أهلاً بك {formatDisplayName(state.user.firstName, state.user.lastName)}</span>
            ) : (
              <span>ALPHA STORE</span>
            )}
          </h1>
          <p className="text-xl md:text-2xl text-gray-300 mb-8 max-w-3xl mx-auto">
            {state.user ? 'مرحباً بك في متجر الألعاب! استكشف أفضل الألعاب والعروض الحصرية' : 'أفضل متجر لبيع مفاتيح الألعاب الأصلية بأسعار تنافسية'}
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            {!state.user && (
              <Link to="/register" className="bg-gradient-to-r from-red-600 to-orange-600 text-white px-8 py-4 rounded-full font-semibold hover:scale-105 transition-all duration-300 shadow-lg hover:shadow-red-500/25">
                إنشاء حساب
              </Link>
            )}
            <button
              onClick={() => {
                const productsSection = document.getElementById('products');
                productsSection?.scrollIntoView({ behavior: 'smooth' });
              }}
              className="bg-white/10 backdrop-blur-md text-white px-8 py-4 rounded-full font-semibold hover:bg-white/20 transition-all duration-300 border border-white/20"
            >
              استعرض الألعاب
            </button>
          </div>
        </div>

        {/* Floating elements */}
        <div className="absolute top-10 left-10 w-20 h-20 bg-red-500/20 rounded-full blur-xl animate-pulse"></div>
        <div className="absolute bottom-10 right-10 w-32 h-32 bg-orange-500/20 rounded-full blur-2xl animate-pulse delay-75"></div>
        <div className="absolute top-1/2 left-1/4 w-16 h-16 bg-pink-500/20 rounded-full blur-lg animate-pulse delay-150"></div>
      </section>

      {/* Featured Banner */}
      <section className="py-8">
        <div className="w-full">
          <div className="bg-gradient-to-r from-orange-500 via-red-500 to-pink-500 rounded-2xl p-8 text-center shadow-2xl relative overflow-hidden">
            <div className="absolute inset-0 bg-white/10 backdrop-blur-sm"></div>
            <div className="relative z-10">
              <div className="flex items-center justify-center mb-4">
                <span className="bg-yellow-400 text-black px-4 py-2 rounded-full font-bold text-sm shadow-lg">جديد</span>
                <span className="text-white text-4xl font-bold mr-4 drop-shadow-lg">عروض حصرية</span>
              </div>
              <p className="text-white text-2xl mb-2 drop-shadow">خصم 20% على جميع مفاتيح Steam و Origin</p>
              <p className="text-yellow-300 font-semibold text-lg drop-shadow">لفترة محدودة - استخدم الكود: EN20</p>
            </div>
          </div>
        </div>
      </section>

      {/* Products Section */}
      <section id="products" className="py-16">
        <div className="w-full">
          <h2 className="text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-orange-600 text-center mb-12">🎮 منتجاتنا</h2>

          {loading ? (
            <div className="text-center py-16">
              <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-red-500"></div>
              <p className="text-white mt-4">جاري التحميل...</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {Array.isArray(games) && games.map((game) => (
                <div key={game._id} className="group relative bg-white/10 backdrop-blur-md rounded-2xl overflow-hidden hover:scale-105 transition-all duration-300 border border-white/20 shadow-xl hover:shadow-2xl hover:shadow-purple-500/20">
                  {/* Game Image */}
                  <div className="relative h-48 overflow-hidden">
                    {game.images && game.images.length > 0 ? (
                      <img
                        src={game.images[0]}
                        alt={game.title}
                        className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                      />
                    ) : (
                      <div className="w-full h-full bg-gradient-to-br from-red-600 to-orange-600 flex items-center justify-center">
                        <span className="text-white text-3xl font-bold">{game.title.charAt(0)}</span>
                      </div>
                    )}

                    {/* Discount Badge */}
                    {game.discount && (
                      <div className="absolute top-3 right-3 bg-gradient-to-r from-red-500 to-pink-500 text-white px-3 py-1 rounded-full text-sm font-bold shadow-lg">
                        -{game.discount}%
                      </div>
                    )}

                    {/* Favorite Button */}
                    <button
                      onClick={() => toggleFavorite(game)}
                      className="absolute top-3 left-3 bg-white/20 backdrop-blur-md p-2 rounded-full hover:bg-white/30 transition-all duration-300 group-hover:scale-110"
                    >
                      <svg className={`w-5 h-5 ${favorites.includes(game._id) ? 'text-red-500 fill-current' : 'text-white'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                      </svg>
                    </button>
                  </div>

                  {/* Game Info */}
                  <div className="p-6">
                    <h3 className="text-xl font-bold text-white mb-2 group-hover:text-red-300 transition-colors">{game.title}</h3>
                    <p className="text-gray-300 text-sm mb-4 line-clamp-2">{game.description}</p>

                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-2">
                        <span className="text-xs bg-red-500/30 text-red-300 px-2 py-1 rounded-full backdrop-blur-sm">{game.platform}</span>
                        <span className="text-xs bg-green-500/30 text-green-300 px-2 py-1 rounded-full backdrop-blur-sm">{game.region}</span>
                      </div>
                    </div>

                    <div className="flex items-center justify-between">
                      <div>
                        {game.discount ? (
                          <div className="flex items-center gap-2">
                            <span className="text-gray-400 line-through text-sm">${game.price}</span>
                            <span className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-orange-600">${(game.price * (1 - game.discount / 100)).toFixed(2)}</span>
                          </div>
                        ) : (
                          <span className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-orange-600">${game.price}</span>
                        )}
                      </div>
                      <button
                        onClick={() => addToCart(game)}
                        className="bg-gradient-to-r from-red-600 to-orange-600 text-white px-4 py-2 rounded-full font-semibold hover:scale-105 transition-all duration-300 text-sm shadow-lg hover:shadow-red-500/25"
                      >
                        أضف للسلة
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-black/40 backdrop-blur-md py-12 mt-20 border-t border-white/10">
        <div className="w-full">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
            <div>
              <h3 className="text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-orange-600 font-bold text-xl mb-4">ALPHA STORE</h3>
              <p className="text-gray-300">أفضل متجر لبيع مفاتيح الألعاب الأصلية</p>
            </div>

            <div>
              <h4 className="text-white font-semibold mb-4">روابط سريعة</h4>
              <ul className="space-y-2">
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">الرئيسية</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">الألعاب</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">العروض</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">اتصل بنا</a></li>
              </ul>
            </div>

            <div>
              <h4 className="text-white font-semibold mb-4">الدعم</h4>
              <ul className="space-y-2">
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">مركز المساعدة</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">سياسة الإرجاع</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">الشروط والأحكام</a></li>
                <li><a href="#" className="text-gray-300 hover:text-red-300 transition-colors">خصوصية</a></li>
              </ul>
            </div>

            <div>
              <h4 className="text-white font-semibold mb-4">تابعنا</h4>
              <div className="flex space-x-reverse space-x-4">
                <a href="#" className="text-gray-300 hover:text-red-400 transition-colors">
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                    <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/>
                  </svg>
                </a>
